Here's how to test `DataFetcher` with modern MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello world", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler("", HttpStatusCode.InternalServerError);
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)] // test itself times out after 5s
    public async Task FetchAsync_RespectsTimeout()
    {
        // Pass TestContext.CancellationToken so the [Timeout] cooperatively cancels
        var handler = new FakeHandler("fast", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange — pre-canceled token
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        var handler = new FakeHandler("data", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_CancelledDuringRequest_ThrowsOperationCanceled()
    {
        // Arrange — cancel after a short delay to simulate mid-request cancellation
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        var handler = new SlowHandler(delay: TimeSpan.FromSeconds(10));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Test doubles ---

    private sealed class FakeHandler(string content, HttpStatusCode status)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            });
        }
    }

    private sealed class SlowHandler(TimeSpan delay) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(delay, cancellationToken); // throws when cancelled
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---|---|
| `sealed` test class | Performance + design clarity |
| `TestContext` via constructor | Enables `readonly`, avoids nullability noise |
| `[Timeout] + _testContext.CancellationToken` | Cooperative timeout — the token fires when time expires |
| `Assert.ThrowsExactlyAsync<T>` | Replaces obsolete `[ExpectedException]`, allows inspecting the exception |
| Custom `HttpMessageHandler` | Avoids mocking frameworks; gives full control over `HttpClient` behavior |
| Pre-canceled `CancellationTokenSource` | Tests the immediate-cancel path |
| `CancellationTokenSource(TimeSpan)` | Tests mid-flight cancellation |

The critical detail: **always pass `_testContext.CancellationToken`** in tests with `[Timeout]`. Without it, the timeout attribute has no way to stop your async code cooperatively — the test would hang until the runner force-kills it.
